(((SELECT id FROM frameworks WHERE name = 'hitrust')), 'HITRUST-09.L-01', 'PHI in Log Statements', 'Detects potential PHI in log and print statements.', 'critical', 'phi_protection', 'HITRUST CSF v11 - 09.L Monitoring System Use', 'Remove PHI from all log statements. Use tokenized identifiers.', 'semantic_pattern', '{"nodeTypes":["call_expression"],"functionNames":["console.log","console.error","console.warn","console.info","logger.info","logger.warn","logger.error","print","logging.info","logging.warning","logging.error"],"checkArguments":true}', 1),
